import React from 'react';
import { useBlockchain } from '../context/BlockchainContext';

const Home: React.FC = () => {
  const { account } = useBlockchain();

  return (
    <div style={{ padding: '2rem', textAlign: 'center' }}>
      <h1>Welcome to the Decentralized KYC Verification System</h1>
      <p>This platform allows users to manage their KYC documents securely on the blockchain.</p>

      {!account ? (
        <div style={{ marginTop: '2rem', padding: '1rem', backgroundColor: '#f8f9fa', borderRadius: '8px', display: 'inline-block' }}>
          <h3>Getting Started</h3>
          <p>Please connect your MetaMask wallet using the button in the navigation bar to proceed.</p>
        </div>
      ) : (
        <div style={{ marginTop: '2rem' }}>
          <h3>You are connected!</h3>
          <p>Use the navigation links above to access your dashboard.</p>
        </div>
      )}
    </div>
  );
};

export default Home;
